/**
 * Reproduction script for: TypeError: Cannot read property 'on' of null
 *
 * When req.socket is null, the middleware should not crash when ws: true is set.
 * Previously, catchUpgradeRequest would be called with null server, causing:
 *   TypeError: Cannot read property 'on' of null
 */

const { createProxyMiddleware } = require('./dist');

// Simulate a request where req.socket is null (as can happen in webpack-dev-server)
const reqWithNullSocket = {
  url: '/test',
  headers: {},
  method: 'GET',
  socket: null, // This is the problematic case
};

// Also test with undefined socket (missing socket property)
const reqWithUndefinedSocket = {
  url: '/test',
  headers: {},
  method: 'GET',
  // socket is undefined
};

function createMockRes() {
  return {
    on: () => {},
    emit: () => {},
    end: () => {},
    writeHead: () => {},
  };
}

// Test 1: req.socket is null
console.log('Test 1: req.socket = null');
try {
  const proxy = createProxyMiddleware({
    target: 'http://localhost:9999',
    ws: true,
  });
  proxy(reqWithNullSocket, createMockRes(), () => {});
  console.log('  PASS: No TypeError thrown');
} catch (err) {
  if (err instanceof TypeError && err.message.includes("Cannot read properties of null")) {
    console.error('  FAIL: TypeError thrown:', err.message);
    process.exitCode = 1;
  } else {
    console.log('  PASS: No TypeError thrown (different error is OK)');
  }
}

// Test 2: req.socket is undefined
console.log('Test 2: req.socket = undefined');
try {
  const proxy = createProxyMiddleware({
    target: 'http://localhost:9999',
    ws: true,
  });
  proxy(reqWithUndefinedSocket, createMockRes(), () => {});
  console.log('  PASS: No TypeError thrown');
} catch (err) {
  if (err instanceof TypeError && err.message.includes("Cannot read properties of undefined")) {
    console.error('  FAIL: TypeError thrown:', err.message);
    process.exitCode = 1;
  } else {
    console.log('  PASS: No TypeError thrown (different error is OK)');
  }
}

// Test 3: With external upgrade (req.socket.server is available via http.createServer)
console.log('Test 3: Normal case with proper server (should still work)');
const http = require('node:http');
const testServer = http.createServer((req, res) => {
  res.end('ok');
});
testServer.listen(0, () => {
  const port = testServer.address().port;
  const proxy = createProxyMiddleware({
    target: 'http://localhost:9999',
    ws: true,
  });

  const req = http.request({ hostname: 'localhost', port, path: '/test' });
  req.end();

  req.on('error', () => {
    // connection error is expected since target doesn't exist
  });

  req.on('socket', (socket) => {
    try {
      const mockRes = createMockRes();
      const mockReq = {
        url: '/test',
        headers: {},
        method: 'GET',
        socket: socket, // real socket
      };
      proxy(mockReq, mockRes, () => {});
      console.log('  PASS: Normal case still works');
    } catch (err) {
      console.error('  FAIL:', err.message);
      process.exitCode = 1;
    }
  });

  setTimeout(() => {
    testServer.close();
    if (!process.exitCode) {
      console.log('\nAll tests passed!');
    }
    process.exit(process.exitCode || 0);
  }, 1000);
});

